      );
      const { stderr, code } = await run([dir]);
      assert.equal(code, 3);
      assert.ok(
        stderr.includes("Error:"),
        `stderr should mention error: ${stderr}`,
      );
    } finally {
      rmSync(dir, { recursive: true });
    }
  });

  it("valid manifest with --dry-run exits 0 and shows plan", async () => {
    const dir = makeTmpDir();
